#include <bits/stdc++.h>
using namespace std;

int main() {
    int N;
    while (cin >> N && N != 0) {
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                int val = min(min(i + 1, j + 1), min(N - i, N - j));
                cout << setw(3) << val;
            }
            cout << endl;
        }
        cout << endl;   // 每个矩阵后输出一个空行
    }
    return 0;
}
